const Q_ECONOMICS_2020_MODEL_I=[{"id": "objective>Economics>2020 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suppose 2011 is given as the base and the national income for 2012 is 3,600,000 and the index number for 2011 is 3200. Calculate the real income for 2012</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,024</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,124</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,224</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,324</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula for calculating real income is   Real income = National income / Index number <br/>  <br/> In this case, the national income for 2012 is 3,600,000 and the index number for 2011 is 3200. <br/>  <br/> Real income = 3,600,000 / 3200 <br/> = 1,124 <br/>  <br/> Therefore, the real income for 2012 is 1,124.</div>", "topic": "NATIONAL INCOME"}, {"id": "objective>Economics>2020 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, the concept of utility means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the monetary value of the goods we consume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the total value of all the goods and services consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the amount of satisfaction we derive from the consumption of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the utilization of goods and services</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, the concept of utility means the amount of satisfaction or pleasure an individual derives from the consumption of goods and services. Utility is a measure of the relative satisfaction or happiness that a person gains from consuming a particular product or service. It is a subjective concept and varies from person to person based on their preferences and individual circumstances.</div>", "topic": "THE THEORY OF CONSUMER BEHAVIOUR"}, {"id": "objective>Economics>2020 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these will cause population to increase</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5% increase in both birth and death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5% increase in death rate with 4% increase in birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10% decrease in both birth and death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4% increase in death rate with 5% increase in birth rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The option that will cause population to increase is 4% increase in death rate with 5% increase in birth rate. <br/>  <br/> Population growth is the increase in the number of people living in a particular area. It is calculated by subtracting the number of deaths from the number of births in a given period. <br/>  <br/> In the option 4% increase in death rate with 5% increase in birth rate, the number of births is increasing by 5%, while the number of deaths is increasing by 4%. This means that the number of people added to the population is still positive, even though it is smaller than the number of people lost to the population.</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2020 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theoretical basis for international trade is the principle of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">comparative advantage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different currencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">international co-operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange between countries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theoretical basis for international trade is the principle of comparative advantage. <br/>  <br/> The principle of comparative advantage, introduced by economist David Ricardo, states that countries should specialize in producing goods and services in which they have a lower opportunity cost compared to other countries. By specializing and trading based on comparative advantage, countries can maximize overall efficiency and benefit from the gains of trade. <br/>  <br/> According to the principle of comparative advantage, even if a country is more efficient in producing all goods compared to another country, it can still benefit from trade by focusing on producing the goods in which it has a relatively greater efficiency or lower opportunity cost. <br/>  <br/> This principle recognizes that countries have different resource endowments, technology levels, and production capabilities, leading to varying costs of production. By engaging in international trade based on comparative advantage, countries can enhance their economic welfare, expand market access, and promote global economic growth. <br/>  <br/> Therefore, the principle of comparative advantage serves as the theoretical basis for international trade.</div>", "topic": "INTERNATIONAL TRADE"}, {"id": "objective>Economics>2020 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following cost items refers to price?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"variable cost\" is the one that refers to price. Variable costs are expenses that change in direct proportion to the level of production or output. In other words, as a company produces more units of a product or provides more services, variable costs increase accordingly. Variable costs are often associated with the cost of raw materials, labor, and other inputs that vary with production levels.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Want satisfying capacity of a commodity is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equilibrium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction that a consumer gets from consuming a good or service. It is a subjective measure, as different consumers will have different levels of utility for the same good or service.</div>", "topic": "THE THEORY OF CONSUMER BEHAVIOUR"}, {"id": "objective>Economics>2020 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation in the Nigerian economy may be increase if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the dollar price of crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sale of company share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government expenditure rise</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sale of government bonds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crude oil is a major export for Nigeria and a significant source of government revenue. When the price of crude oil rises, the government has more money to spend. This can lead to increased demand for goods and services, which can drive up prices.</div>", "topic": "INFLATION"}, {"id": "objective>Economics>2020 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market system, trading can only take place when the market is not working efficiently. Equilibrium price and quantity under perfect competition is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MC = AR =TR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TC =AR =P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = AR = P = D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = AR = TC</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium price and quantity under perfect competition is MC = AR = P = D. <br/>  <br/> In a perfectly competitive market, there are many buyers and sellers, and no one buyer or seller has a significant impact on the market price. As a result, the market price is determined by the interaction of supply and demand. <br/>  <br/> The marginal cost (MC) is the additional cost incurred by producing one more unit of output. The average revenue (AR) is the total revenue divided by the number of units sold. The price (P) is the amount that buyers are willing to pay for each unit of output. The demand (D) is the quantity that buyers are willing to buy at each price. <br/>  <br/> At equilibrium, the MC is equal to the AR, which is also equal to the price, which is also equal to the demand. This means that firms are producing the quantity of output that minimizes their costs and maximizes their profits.</div>", "topic": "MARKET STRUCTURE"}, {"id": "objective>Economics>2020 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Market for Semovita</strong> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"><strong>Price per tin</strong></td><td style=\"border:1px solid black;text-align:center;\"> <strong>Demand per week</strong></td><td style=\"border:1px solid black;text-align:center;\"> <strong>Supply per week</strong></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#6</td><td style=\"border:1px solid black;text-align:center;\"> 0 tins</td><td style=\"border:1px solid black;text-align:center;\"> 45 tins</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#5</td><td style=\"border:1px solid black;text-align:center;\"> 5 tins</td><td style=\"border:1px solid black;text-align:center;\"> 35 tins</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#4</td><td style=\"border:1px solid black;text-align:center;\"> 10 tins</td><td style=\"border:1px solid black;text-align:center;\"> 25 tins</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#3</td><td style=\"border:1px solid black;text-align:center;\"> 15 tins</td><td style=\"border:1px solid black;text-align:center;\"> 15 tins</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#2</td><td style=\"border:1px solid black;text-align:center;\"> 20 tins</td><td style=\"border:1px solid black;text-align:center;\"> 5 tins</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">#1</td><td style=\"border:1px solid black;text-align:center;\"> 25 tins</td><td style=\"border:1px solid black;text-align:center;\"> 0 tins</td></tr></table></div> <br/>  <br/> At a price of #5, the excess supply is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">45 tins per week</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15 tins per week</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 tins per week</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 tins per week</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At a price of #5, the quantity demanded is 5 tins per week and the quantity supplied is 35 tins per week. <br/>  <br/>  Therefore, the excess supply is 35 tins per week - 5 tins per week  <br/>  <br/> = 30 tins per week.</div>", "topic": "THE THEORY OF SUPPLY"}, {"id": "objective>Economics>2020 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that Qd = 15 - 2P and Qs = 5 + 3P, determine the equilibrium price.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">#6.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#3.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#5.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">#2.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qd = Qs <br/> 15 - 2P = 5 + 3P <br/> Solving for P, we get: <br/>  <br/> 5P = 10 <br/> P = 2 <br/>  <br/> Therefore, the equilibrium price is #2.00.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A development plan covering a period of fifteen years is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perspective plan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short term plan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium term plan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combined plan</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A development plan covering a period of fifteen years is a perspective plan. A perspective plan is a long-term plan that outlines the goals and objectives of a country or organization over a period of 10 to 20 years. It is a broad plan that does not go into much detail.</div>", "topic": "ECONOMIC GROWTH AND DEVELOPMENT"}, {"id": "objective>Economics>2020 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Money becomes a very poor store of value in the period of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stable price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recession</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inflation is the general increase in prices over time, which erodes the purchasing power of money. When there is high inflation, the real value of money decreases rapidly. This means that the same amount of money can buy fewer goods and services in the future compared to the present. As a result, money is not a reliable store of value during periods of significant inflation because its real value diminishes over time. <br/>  <br/> In contrast, during periods of stable prices or deflation (where prices are generally decreasing), the real value of money tends to remain relatively stable or even increase, making money a better store of value in those circumstances.</div>", "topic": "INFLATION"}, {"id": "objective>Economics>2020 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scientific method requires that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the scientist be objective</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the scientist use precision equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only correct theories are tested</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only incorrect theories are tested</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scientific method requires that the scientist be objective, meaning that they should not let their personal beliefs or biases influence their research. </div>", "topic": "METHODS OF ECONOMIC ANALYSIS"}, {"id": "objective>Economics>2020 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For an economy that is in a recession, the actual unemployment rate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than the natural rate of unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the natural rate of unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the natural rate of unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than the growth rate of economy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an economy that is in a recession, the actual unemployment rate is typically \"greater than the natural rate of unemployment.\" <br/>  <br/> The natural rate of unemployment represents the level of unemployment that exists even when the economy is operating at its full potential and there is no cyclical unemployment (which occurs during economic downturns like recessions). During a recession, the overall level of economic activity is lower than its potential, leading to higher unemployment rates, which are greater than the natural rate of unemployment. This excess unemployment is often referred to as \"cyclical unemployment\" and is a characteristic feature of economic downturns.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT"}, {"id": "objective>Economics>2020 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Full equilibrium requires that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MR = MC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TR > TC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = MR and AC - AR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MR = MC = AR = AC</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MR is the marginal revenue, which is the additional revenue that a firm earns by selling one more unit of output. MC is the marginal cost, which is the additional cost that a firm incurs by producing one more unit of output. AR is the average revenue, which is the total revenue divided by the number of units sold. AC is the average cost, which is the total cost divided by the number of units sold. <br/>  <br/> When MR = MC, the firm is maximizing its profits. This is because the firm is producing the quantity of output where the additional revenue that it earns from selling one more unit is equal to the additional cost that it incurs in producing that unit. <br/>  <br/> When AR = AC, the firm is breaking even. This is because the firm is earning exactly enough revenue to cover its costs.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of CURRIE was 480,000 in December 1980, out of which 60% were female. If within one year no birth were recorded, but 5% of the male died, what will be the population of CURRIE in December 1981.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">288,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">470,400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">96,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">192,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population of Afaka in December 1980 that were females is 60/100  x 480000 = 288000 <br/>  <br/> The population of Afaka in December 1980 that were males is 480000-288000 = 192000 <br/>  <br/> If 5% of the males died, the number of males that died is 5/100  x 192000 = 9600 <br/>  <br/> The population of males in December 1981 is 192000-9600 = 182400 <br/>  <br/> The total population of Afaka in December 1981 is 182400+288000 = 470400 <br/>  <br/> So the answer is 470,400</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2020 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A foreign exchange market where there is the official operating side by side with the autonomous market is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the second tier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-operation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange currency</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The official market is the market where the central bank of a country operates. The autonomous market is the market where other participants, such as banks and businesses, operate. The second tier foreign exchange market is a market that is created when the official market and the autonomous market are allowed to operate side by side. <br/>  <br/> The second tier foreign exchange market can help to improve the efficiency of the foreign exchange market by providing more liquidity and competition. It can also help to reduce the volatility of the foreign exchange market by providing a more diversified pool of buyers and sellers.</div>", "topic": "INTERNATIONAL TRADE"}, {"id": "objective>Economics>2020 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economy is in the midst of a recession. An example of a government policy aimed at moving the economy back on the path of positive growth is an</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in government spending on infrastructure improvements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the property tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in cash transfers to the very poor</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a government policy aimed at moving the economy back on the path of positive growth during a recession is an \"increase in government spending on infrastructure improvements.\" This type of fiscal policy, often referred to as expansionary fiscal policy, involves the government increasing its expenditures on infrastructure projects, such as building roads, bridges, schools, and other public facilities. This increased government spending can stimulate economic activity, create jobs, and boost overall demand in the economy, helping to counter the negative effects of a recession.</div>", "topic": "ECONOMIC GROWTH AND DEVELOPMENT"}, {"id": "objective>Economics>2020 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below represents a production function. At which of the point does diminishing return sets in? <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The point of diminishing returns sets in at point K, where the production function is at its maximum. This means that any additional units of labor will produce less output.</div>", "topic": "THE THEORY OF PRODUCTION"}, {"id": "objective>Economics>2020 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The national income of a country indicates that the Gross National Income was $417,700 million and Gross Domestic Product was 1,416,800. The difference of 14,900 million represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debts repayment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">investment abroad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net income from abroad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital consumption</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross national income (GNI) is the total income earned by a country's residents, regardless of where that income is generated. Gross domestic product (GDP) is the total value of goods and services produced within a country's borders. <br/>  <br/> The difference between GNI and GDP is the net income from abroad. This is the income that residents of a country earn from investments and work abroad, minus the income that foreigners earn from investments and work within the country. <br/>  <br/> In this case, the GNI is 417,700 million and the GDP is 1,416,800 million. The difference is 14,900 million. This means that the net income from abroad is 14,900 million.</div>", "topic": "NATIONAL INCOME"}, {"id": "objective>Economics>2020 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not true when price is above equilibrium price?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is shortage of the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the quantity supplied exceeds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pressure on the commodity price is downward</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is surplus of the commodity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the price is above the equilibrium price (i.e., it is in a situation known as excess demand or shortage), there is upward pressure on the commodity price. This upward pressure occurs because consumers are willing to pay more for the commodity than the current market price, and suppliers may respond by raising prices in response to the excess demand. <br/>  <br/> The other statements are generally true in a situation where the price is above the equilibrium price: <br/> -  There is a shortage of the commodity because the quantity demanded exceeds the quantity supplied. <br/> -   The quantity supplied is less than the quantity demanded. <br/> -  There is a surplus of the commodity when the price is below the equilibrium price, not when it's above the equilibrium price.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Development plan have not been successful in some developing country largely because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">very large working population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing level consumption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity of industrial raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of skilled labour and experts</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Development plans have not been successful in some developing countries largely because of shortage of skilled labor and experts. <br/>  <br/> Here are some of the reasons why developing countries often lack skilled labor and experts: <br/> -  Lack of investment in education and training: Many developing countries do not invest enough in education and training, which means that there is a shortage of qualified workers. <br/> -   Brain drain: Many skilled workers from developing countries migrate to developed countries in search of better opportunities, which further worsens the shortage of skilled labor. <br/> -   Inadequate infrastructure: The lack of adequate infrastructure, such as roads, schools, and hospitals, makes it difficult to attract and retain skilled workers. <br/> -  Political instability: Political instability can deter investment and make it difficult to attract and retain skilled workers.</div>", "topic": "ECONOMIC GROWTH AND DEVELOPMENT"}, {"id": "objective>Economics>2020 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a commodity X sold for #25 per unit, 50 units of commodity Y were purchased. With an increase in the price of commodity X to #50 per unit, the demand for commodity Y fells to 20 units. The two commodities can be classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermediate and final</div>", "<div style=\"font-family:Cambria;font-size:17px;\">durable and non-durable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">complements</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Substitute goods are goods that can be used in place of each other. For example, butter and margarine are substitutes. When the price of one substitute good increases, the demand for the other substitute good increases. <br/>  <br/> In the question , the demand for commodity Y decreased when the price of commodity X increased. This suggests that the two commodities are substitutes.</div>", "topic": "THE THEORY OF DEMAND"}, {"id": "objective>Economics>2020 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the same basket of goods which cost &#8358;12.00 in 1985 cost &#8358;15.000 in 1987, the price index for 1987 is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">125</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price index = (Price of current year / Price of previous year) * 100 <br/>  <br/> = (₦15.00 / ₦12.00) x 100 <br/>  <br/>  = 1.25 x 100 <br/>  <br/> = 125%</div>", "topic": "INFLATION"}, {"id": "objective>Economics>2020 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price elasticity of demand for a good is 0.43, an increase in the price of the good will result in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a net gain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a net loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in profit by 43%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in profit by 43%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the price elasticity of demand for a good is 0.43 (which is less than 1), it indicates that the demand for the good is inelastic. Inelastic demand means that the percentage change in quantity demanded is less than the percentage change in price. <br/>  <br/> An increase in price will lead to a proportionally smaller decrease in quantity demanded due to the inelastic nature of demand. As a result, total revenue (which is the product of price and quantity) will increase, leading to a net gain.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2020 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Price can be defined as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A rate of exchange of value of one commodity for another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A medium of exchange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The unit of account</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price can be defined as a rate of exchange of value of one commodity for another. It is the amount of money that is paid for a good or service. Prices are determined by the interaction of supply and demand.</div>", "topic": "THE THEORY OF PRICE DETERMINATION"}, {"id": "objective>Economics>2020 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of a country x in 1990 was 30 million.  The births were 450,000 while it recorded 210,000 deaths. If the same year, its immigrants were 20,000 and 10,000 of its citizens left the country. Calculate the total population of the country at the end of the 1990.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25,350,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24,250,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32,250,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24,750,000</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total Population at the End of the Year = Initial Population + Births - Deaths + Immigration - Emigration <br/>  <br/> Initial Population = 30,000,000 <br/> Births = 450,000 <br/> Deaths = 210,000 <br/> Immigration = 20,000 <br/> Emigration = 10,000 <br/>  <br/> Now, plug these values into the formula: <br/>  <br/> Total Population at the End of 1990 = 30,000,000 + 450,000 - 210,000 + 20,000 - 10,000 <br/>  <br/> Total Population at the End of 1990 = 30,250,000</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2020 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The regulatory authority of the capital market in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Central Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchanges Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Deposit Insurance Corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stock Exchange Market</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Securities and Exchange Commission is responsible for regulating and overseeing various aspects of the Nigerian capital market, including the registration and regulation of securities, the protection of investors, the supervision of market operators, and the development and enforcement of rules and regulations governing the capital market. It plays a crucial role in maintaining the integrity and transparency of the Nigerian capital market and ensuring the protection of investors' interests.</div>", "topic": "FINANCIAL INSTITUTION"}, {"id": "objective>Economics>2020 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution aims at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substituting agricultural products with industrial ones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producing in a country goods that are formally imported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devalue the currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">de-emphasize import-substitution industries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution is a trade and economic policy that advocates replacing foreign imports with domestic production. It is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products. <br/>  <br/> The goal of import substitution is to create jobs, develop domestic industries, and reduce the balance-of-payments deficit. It can be implemented through a variety of measures, such as tariffs, quotas, and subsidies.</div>", "topic": "ECONOMIC GROWTH AND DEVELOPMENT"}, {"id": "objective>Economics>2020 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the table below, the price elasticity of supply is <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">price (#)</td><td style=\"border:1px solid black;text-align:center;\"> Qty(bags)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">60</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">120</td></tr></table></div></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">es = ∆Qd/ ∆P    x P/Qd <br/>  <br/> ∆Qd = Q2 - Q1 <br/> ∆P = P2 - P1 <br/> P = P1 <br/> Qd = Q1 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">e</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">120 - 60<hr size=\"1\" />2 - 1</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">1<hr size=\"1\" />60</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />1</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">1<hr size=\"1\" />60</td></tr></table></div> <br/>  <br/> = 1</div>", "topic": "THE THEORY OF SUPPLY"}, {"id": "objective>Economics>2020 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a producer sells 1kg of rice for ₦20 and his marginal products is 100kg, what is the highest wage he can pay the marginal labourer?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 20.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦. 50.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 100.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ₦ 200.00</div>"], "answer": -1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the highest wage the producer can pay the marginal laborer, you can use the concept of marginal product and the marginal revenue product of labor. <br/>  <br/> The marginal revenue product of labor (MRP) is the additional revenue generated by employing one more unit of labor. In this case, the marginal product is given as 100kg. <br/>  <br/> If the producer sells 1kg of rice for ₦20, then the additional revenue from the marginal product is: <br/>  <br/> MRP = Price × Marginal Product <br/> = ₦20/kg × 100kg <br/> = ₦2000 <br/>  <br/> So, the highest wage the producer can pay the marginal laborer is ₦2000.</div>", "topic": "THEORY OF COST AND REVENUE"}, {"id": "objective>Economics>2020 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public expenditure creates expansionary effects in the economy when its is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in excess of government revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">channeled into capital projects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverted into imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">financed through oil revenue</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Expansionary fiscal policy is a policy that involves increasing government spending or decreasing taxes in order to stimulate the economy. When the government spends more money than it receives in revenue, it creates a budget deficit. This deficit can be financed through borrowing, which puts more money into the economy and can lead to increased economic activity.</div>", "topic": "PUBLIC FINANCE"}, {"id": "objective>Economics>2020 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the distribution channels for goods and services, the middleman's mark -up margin provides a rough measure for the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quantity discounts allowed final consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reward for business entrepreneurship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effectiveness of government control over the economy's marketing channels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extend of exploitation of the final consumer</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The middleman's mark-up margin provides a rough measure for the extent of exploitation of the final consumer. <br/>  <br/> The middleman's mark-up margin is the difference between the price that the middleman pays for the goods and the price that the middleman sells the goods for. The higher the mark-up margin, the more the middleman is making in profit. <br/>  <br/> If the mark-up margin is high, it suggests that the middleman is making a large profit at the expense of the final consumer. This is because the final consumer is paying more for the goods than they need to.</div>", "topic": "DISTRIBUTIVE TRADE"}, {"id": "objective>Economics>2020 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the table below to answer the question</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Variable factor</td><td style=\"border:1px solid black;text-align:center;\"> Total product</td><td style=\"border:1px solid black;text-align:center;\"> Marginal Product</td><td style=\"border:1px solid black;text-align:center;\"> Average Product</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">3</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">24</td><td style=\"border:1px solid black;text-align:center;\">18</td><td style=\"border:1px solid black;text-align:center;\">8</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\"> X</td><td style=\"border:1px solid black;text-align:center;\"> 12</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">Z</td><td style=\"border:1px solid black;text-align:center;\">25</td><td style=\"border:1px solid black;text-align:center;\">14.6</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">93</td><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">Y</td></tr></table></div> <br/>  <br/> The marginal product X is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the marginal product, we use the formular:  Change in TP/Change in variable factor <br/>  <br/> = 48 - 24/ 4 - 3 <br/>  <br/> X = 24</div>", "topic": "THE THEORY OF PRODUCTION"}, {"id": "objective>Economics>2020 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the table below to answer the question</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Variable factor</td><td style=\"border:1px solid black;text-align:center;\"> Total product</td><td style=\"border:1px solid black;text-align:center;\"> Marginal Product</td><td style=\"border:1px solid black;text-align:center;\"> Average Product</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">3</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">24</td><td style=\"border:1px solid black;text-align:center;\">18</td><td style=\"border:1px solid black;text-align:center;\">8</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\"> X</td><td style=\"border:1px solid black;text-align:center;\"> 12</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">Z</td><td style=\"border:1px solid black;text-align:center;\">25</td><td style=\"border:1px solid black;text-align:center;\">14.6</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">93</td><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">Y</td></tr></table></div> <br/> The total product Z is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">73</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">118</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the TP (Z) , we use the formular = Ap   x Variable factor <br/>  <br/> = 14.5  x 5 <br/>  <br/> = 73</div>", "topic": "THE THEORY OF PRODUCTION"}, {"id": "objective>Economics>2020 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the table below to answer the question</strong> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Variable factor</td><td style=\"border:1px solid black;text-align:center;\"> Total product</td><td style=\"border:1px solid black;text-align:center;\"> Marginal Product</td><td style=\"border:1px solid black;text-align:center;\"> Average Product</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">3</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">24</td><td style=\"border:1px solid black;text-align:center;\">18</td><td style=\"border:1px solid black;text-align:center;\">8</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\"> X</td><td style=\"border:1px solid black;text-align:center;\"> 12</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">Z</td><td style=\"border:1px solid black;text-align:center;\">25</td><td style=\"border:1px solid black;text-align:center;\">14.6</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">93</td><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">Y</td></tr></table></div> <br/> The average product Y is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the AP (Y), we use the formular = TP/Variable factor <br/>  <br/> = 93/6 <br/>  <br/> = 15.5</div>", "topic": "THE THEORY OF PRODUCTION"}, {"id": "objective>Economics>2020 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To assure that the non price determinant of demand and supply were not ignored, we use assumption of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Demand and supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Constant supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Other thing being equal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The assumption that is used to assure that the non-price determinants of demand and supply are not ignored is ceteris paribus, which means all other things being equal. This assumption is used to isolate the effect of one variable on another, such as the effect of price on quantity demanded. <br/>  <br/> When we use the ceteris paribus assumption, we are saying that all other factors that affect demand and supply are held constant. This allows us to focus on the relationship between price and quantity demanded or price and quantity supplied.</div>", "topic": "THE THEORY OF DEMAND"}, {"id": "objective>Economics>2020 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason why nations engage in international trade is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it allows free movement of factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it makes possible the use of capital-intensive method of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nations are substantially different in their endowments of economic resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it affords the trading nations the opportunity to earn high profit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major reason why nations engage in international trade is that nations are substantially different in their endowments of economic resources. <br/>  <br/> Different countries have different natural resources, labor, and capital. This means that they can produce different goods and services at different costs. <br/>  <br/> For example, China has a lot of labor and few natural resources. This means that China can produce labor-intensive goods, such as clothing, at a lower cost than other countries. <br/>  <br/> The United States has a lot of natural resources and capital. This means that the United States can produce capital-intensive goods, such as automobiles, at a lower cost than other countries. <br/>  <br/> By trading with each other, countries can specialize in producing the goods and services that they are best at producing. This allows them to produce more goods and services overall and to enjoy a higher standard of living.</div>", "topic": "INTERNATIONAL TRADE"}, {"id": "objective>Economics>2020 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following classical economist propounded the theory of population</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thomas Robert Malthus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adam Smith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alfred Marshal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Malthus is best known for his work \"An Essay on the Principle of Population,\" in which he discussed the relationship between population growth and its consequences for society and resources. Adam Smith and Alfred Marshall made significant contributions to economics, but they are not specifically known for theories of population as Malthus is.</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2020 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Comparative advantage implies that a country will specialize in producing the commodity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">with the highest opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for which output workers is lower than in other countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">with the lowest opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">for which output per workers is same with those of other countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Comparative advantage is an economic concept that suggests countries should specialize in producing goods or services in which they have a comparative advantage, meaning they can produce those items at a lower opportunity cost compared to other countries. By doing so and engaging in international trade, countries can maximize their overall production and consumption possibilities and benefit from the efficiencies gained through specialization. The idea is to allocate resources where they are most efficient, which, in turn, leads to lower opportunity costs and increased overall economic welfare.</div>", "topic": "INTERNATIONAL TRADE"}];
